    questions: [ {q:"Did the robbery occur before the US invaded Iraq?", a_en:"Yes", a_tr:"Evet"}, {q:"Was it ordered by Saddam Hussein?", a_en:"Yes", a_tr:"Evet"}, {q:"Did he send his son with a handwritten note?", a_en:"Yes", a_tr:"Evet"}, {q:"Were the bank workers unable to say no?", a_en:"Yes", a_tr:"Evet"}, {q:"Did they load the money into small cars?", a_en:"No", a_tr:"Hayır"}, {q:"Did they take about 1 billion dollars?", a_en:"Yes", a_tr:"Evet"}, {q:"Are hundreds of millions of dollars still missing?", a_en:"Yes", a_tr:"Evet"} ]
